export function add_cookies_to_headers(headers, cookies) {
	for (const new_cookie of cookies) {
		const { name, value, options } = new_cookie;
		headers.append('set-cookie', serialize(name, value, options));

		// special case — for routes ending with .html, the route data lives in a sibling
		// `.html__data.json` file rather than a child `/__data.json` file, which means
		// we need to duplicate the cookie
		if (options.path.endsWith('.html')) {
			const path = add_data_suffix(options.path);
			headers.append('set-cookie', serialize(name, value, { ...options, path }));
		}
	}
}

export function json(data, init) {
	// TODO deprecate this in favour of `Response.json` when it's
	// more widely supported
	const body = JSON.stringify(data);

	// we can't just do `text(JSON.stringify(data), init)` because
	// it will set a default `content-type` header. duplicated code
	// means less duplicated work
	const headers = new Headers(init?.headers);
	if (!headers.has('content-length')) {
		headers.set('content-length', text_encoder.encode(body).byteLength.toString());
	}

	if (!headers.has('content-type')) {
		headers.set('content-type', 'application/json');
	}

	return new Response(body, {
		...init,
		headers
	});
}

export function OnDirective(node, context) {
	if (!node.expression) {
		context.state.analysis.needs_props = true;
	}

	let handler = build_event_handler(node.expression, node.metadata.expression, context);

	for (const modifier of modifiers) {
		if (node.modifiers.includes(modifier)) {
			handler = b.call('$.' + modifier, handler);
		}
	}

	const capture = node.modifiers.includes('capture');
	const passive =
		node.modifiers.includes('passive') ||
		(node.modifiers.includes('nonpassive') ? false : undefined);

	return build_event(context, node.name, handler, capture, passive, false);
}

export function build_style_directives_object(
	style_directives,
	context,
	memoizer = context.state.memoizer
) {
	const normal = b.object([]);
	const important = b.object([]);

	const metadata = new ExpressionMetadata();

	for (const d of style_directives) {
		metadata.merge(d.metadata.expression);

		const expression =
			d.value === true
				? build_getter(b.id(d.name), context.state)
				: build_attribute_value(d.value, context).value;

		const object = d.modifiers.includes('important') ? important : normal;
		object.properties.push(b.init(d.name, expression));
	}

	const directives = important.properties.length ? b.array([normal, important]) : normal;

	return memoizer.add(directives, metadata);
}

export function bind_playback_rate(media, get, set = get) {
	// Needs to happen after element is inserted into the dom (which is guaranteed by using effect),
	// else playback will be set back to 1 by the browser
	effect(() => {
		var value = Number(get());

		if (value !== media.playbackRate && !isNaN(value)) {
			media.playbackRate = value;
		}
	});

	// Start listening to ratechange events after the element is inserted into the dom,
	// else playback will be set to 1 by the browser
	effect(() => {
		listen(media, ['ratechange'], () => {
			set(media.playbackRate);
		});
	});
}

export async function tick() {
	if (async_mode_flag) {
		return new Promise((f) => {
			// Race them against each other - in almost all cases requestAnimationFrame will fire first,
			// but e.g. in case the window is not focused or a view transition happens, requestAnimationFrame
			// will be delayed and setTimeout helps us resolve fast enough in that case
			requestAnimationFrame(() => f());
			setTimeout(() => f());
		});
	}

	await Promise.resolve();

	// By calling flushSync we guarantee that any pending state changes are applied after one tick.
	// TODO look into whether we can make flushing subsequent updates synchronously in the future.
	flushSync();
}

export function resolve_explicit_env_entry(config) {
	const resolved = resolve_entry(path.join(config.files.src, 'env'));

	if (resolved) {
		if (config.experimental.explicitEnvironmentVariables) {
			return resolved;
		}

		if (!warned) {
			console.warn(
				`${path.relative(process.cwd(), resolved)} requires the \`experimental.explicitEnvironmentVariables\` flag to be set`
			);
			warned = true;
		}
	} else if (config.experimental.explicitEnvironmentVariables) {
		console.warn(
			'experimental.explicitEnvironmentVariables was set, but no src/env.ts or src/env.js file could be found'
		);
	}

	return null;
}

function processSvelteTemplate(
    str: MagicString,
    parse: typeof import('svelte/compiler').parse,
    options: {
        emitOnTemplateError?: boolean;
        namespace?: string;
        accessors?: boolean;
        mode?: 'ts' | 'dts';
        typingsNamespace?: string;
        svelte5Plus: boolean;
        emitJsDoc?: boolean;
        isTsFile?: boolean;
        rewriteExternalImports?: RewriteExternalImportsOptions;
    }
): TemplateProcessResult {
    const { htmlxAst, tags } = parseHtmlx(str.original, parse, options);
    return convertHtmlxToJsx(str, htmlxAst, tags, options);
}

function setMultiselectKeyListeners(want) {
  if (want && !multiselectKeyListenersAttached) {
    window.addEventListener("keydown", syncModifierFromKeyboard, true);
    window.addEventListener("keyup", syncModifierFromKeyboard, true);
    window.addEventListener("blur", clearMultiselectModifierKeys);
    document.addEventListener("visibilitychange", onDocumentVisibilityChange);
    multiselectKeyListenersAttached = true;
  } else if (!want && multiselectKeyListenersAttached) {
    window.removeEventListener("keydown", syncModifierFromKeyboard, true);
    window.removeEventListener("keyup", syncModifierFromKeyboard, true);
    window.removeEventListener("blur", clearMultiselectModifierKeys);
    document.removeEventListener(
      "visibilitychange",
      onDocumentVisibilityChange,
    );
    multiselectKeyListenersAttached = false;
    multiselectModifierActive = false;
  }
}

getOriginalPosition(generatedPosition: Position): Position {
    if (this.scriptMapper?.isInTranspiledFragment(generatedPosition)) {
        return this.scriptMapper.getOriginalPosition(generatedPosition);
    }
    if (this.styleMapper?.isInTranspiledFragment(generatedPosition)) {
        return this.styleMapper.getOriginalPosition(generatedPosition);
    }

    // Position is not in fragments, but we still need to account for
    // the length differences of the fragments before the position.
    let offset = offsetAt(generatedPosition, this.transpiled);
    for (const fragmentInfo of this.fragmentInfos) {
        if (offset > fragmentInfo.end) {
            offset += fragmentInfo.diff;
        }
    }
    return this.parent.positionAt(offset);
}

run(thunks) {
	const context = ssr_context;

	let promise = Promise.resolve(thunks[0]());
	const promises = [promise];

	for (const fn of thunks.slice(1)) {
		promise = promise.then(() => {
			const previous_context = ssr_context;
			set_ssr_context(context);

			try {
				return fn();
			} finally {
				set_ssr_context(previous_context);
			}
		});

		promises.push(promise);
	}

	// prevent unhandled rejections, and attach the promise to the renderer instance
	// so that rejections correctly cause rendering to fail
	promise.catch(noop);
	this.promise = promise;

	return promises;
}

function appendOneWayBinding(
    attr: BaseDirective,
    assignment: string,
    element: Element | InlineComponent,
    leadingComments: TransformationArray,
    trailingComments: TransformationArray
) {
    const expression = attr.expression;
    const end = getEnd(expression);
    const hasTypeAnnotation = expression.typeAnnotation || isTypescriptNode(expression);
    const array: TransformationArray = [
        ...leadingComments,
        [expression.start, end],
        assignment + (hasTypeAnnotation ? '' : ';'),
        ...trailingComments
    ];
    if (hasTypeAnnotation) {
        array.push([end, expression.end], ';');
    }
    element.appendToStartEnd(array);
}

async function copyMarkdown() {
  if (copying) return;
  copying = true;

  let markdown = markdownCache.get(component);

  if (!markdown) {
    const response = await fetch(markdownUrl);

    if (response.ok) {
      markdown = await response.text();
      markdownCache.set(component, markdown);
    }
  }

  if (markdown) {
    await navigator.clipboard.writeText(markdown);
    if (!copied) {
      copied = true;
      copyTimeout = setTimeout(() => {
        copied = false;
        copyTimeout = null;
      }, 2000);
    }
  }

  copying = false;
}

openDocument(
    textDocument: Pick<TextDocumentItem, 'text' | 'uri'>,
    openedByClient: boolean
): Document {
    textDocument = {
        ...textDocument,
        uri: normalizeUri(textDocument.uri)
    };

    let document: Document;
    if (this.documents.has(textDocument.uri)) {
        document = this.documents.get(textDocument.uri)!;
        // open state should only be updated when the document is closed
        document.openedByClient ||= openedByClient;
        document.setText(textDocument.text);
        this.notify('documentChange', document);
    } else {
        document = this.createDocument(textDocument);
        document.openedByClient = openedByClient;
        this.documents.set(textDocument.uri, document);
        this.notify('documentOpen', document);
    }

    return document;
}

getSelectionRange(document: Document, position: Position): SelectionRange | null {
    if (!this.featureEnabled('selectionRange') || !isInTag(position, document.styleInfo)) {
        return null;
    }

    const cssDocument = this.getCSSDoc(document);
    const [range] = this.getLanguageService(extractLanguage(cssDocument)).getSelectionRanges(
        cssDocument,
        [cssDocument.getGeneratedPosition(position)],
        cssDocument.stylesheet
    );

    if (!range) {
        return null;
    }

    return mapSelectionRangeToParent(cssDocument, range);
}

findDocumentHighlight(document: Document, position: Position): DocumentHighlight[] | null {
    const cssDocument = this.getCSSDocAtPosition(document, position);
    if (cssDocument) {
        if (shouldExcludeDocumentHighlights(cssDocument)) {
            return wordHighlightForTag(document, position, document.styleInfo, wordPattern);
        }

        return this.findDocumentHighlightInternal(cssDocument, position);
    }

    const attributeContext = getAttributeContextAtPosition(document, position);
    if (
        attributeContext &&
        this.inStyleAttributeWithoutInterpolation(attributeContext, document.getText())
    ) {
        const [start, end] = attributeContext.valueRange;
        return this.findDocumentHighlightInternal(
            new StyleAttributeDocument(document, start, end, this.cssLanguageServices),
            position
        );
    }

    return null;
}

findDocumentHighlight(document: Document, position: Position): DocumentHighlight[] | null {
    const html = this.documents.get(document);
    if (!html) {
        return null;
    }

    const templateResult = wordHighlightForTag(
        document,
        position,
        document.templateInfo,
        wordPattern
    );

    if (templateResult) {
        return templateResult;
    }

    const node = html.findNodeAt(document.offsetAt(position));
    if (possiblyComponent(node)) {
        return null;
    }
    const result = this.lang.findDocumentHighlights(document, position, html);

    if (!result.length) {
        return null;
    }

    return result;
}

export async function getDiagnostics(
    document: Document,
    svelteDoc: SvelteDocument,
    settings: CompilerWarningsSettings,
    cancellationToken?: CancellationToken
): Promise<Diagnostic[]> {
    const config = await svelteDoc.config;
    if (config?.loadConfigError) {
        return getConfigLoadErrorDiagnostics(config.loadConfigError, config.configSource);
    }

    if (cancellationToken?.isCancellationRequested) {
        return [];
    }

    try {
        return await tryGetDiagnostics(document, svelteDoc, settings, cancellationToken);
    } catch (error) {
        return getPreprocessErrorDiagnostics(document, error);
    }
}

static async create(
    document: Document,
    preprocessors: PreprocessorGroup | PreprocessorGroup[] = []
) {
    const { transpiled, processedScripts, processedStyles } = await transpile(
        document,
        preprocessors
    );
    const scriptMapper = SvelteFragmentMapper.createScript(
        document,
        transpiled,
        processedScripts
    );
    const styleMapper = SvelteFragmentMapper.createStyle(document, transpiled, processedStyles);

    return new FallbackTranspiledSvelteDocument(
        document,
        transpiled,
        scriptMapper,
        styleMapper
    );
}

async getCompletions(
    document: Document,
    position: Position,
    completionContext?: CompletionContext,
    cancellationToken?: CancellationToken
): Promise<AppCompletionList<CompletionResolveInfo> | null> {
    if (!this.featureEnabled('completions')) {
        return null;
    }

    const tsDirectiveCommentCompletions = getDirectiveCommentCompletions(
        position,
        document,
        completionContext
    );

    const completions = await this.completionProvider.getCompletions(
        document,
        position,
        completionContext,
        cancellationToken
    );

    if (completions && tsDirectiveCommentCompletions) {
        return CompletionList.create(
            completions.items.concat(tsDirectiveCommentCompletions.items),
            completions.isIncomplete
        );
    }

    return completions ?? tsDirectiveCommentCompletions;
}

async function loadSvelteConfig(configFilePath: string): Promise<LoadConfigResult> {
    try {
        const config = (await dynamicImport(pathToFileURL(configFilePath).href))?.default;
        if (!config) {
            throw new Error(
                'Missing exports in the config. Make sure to include "export default config" or "module.exports = config"'
            );
        }

        return {
            config,
            configFilePath,
            configSource: 'svelte'
        };
    } catch (error) {
        return {
            error,
            configFilePath,
            configSource: 'svelte'
        };
    }
}

function decorateSyntacticDiagnostics(
    ls: ts.LanguageService,
    info: ts.server.PluginCreateInfo,
    typescript: typeof ts,
    logger: Logger
): void {
    const getSyntacticDiagnostics = ls.getSyntacticDiagnostics;
    ls.getSyntacticDiagnostics = (fileName: string) => {
        // Diagnostics inside Svelte files are done
        // by the svelte-language-server / Svelte for VS Code extension
        if (isSvelteFilePath(fileName)) {
            return [];
        }

        const kitDiagnostics = getKitDiagnostics(
            'getSyntacticDiagnostics',
            fileName,
            info,
            typescript,
            logger
        );
        return kitDiagnostics ?? getSyntacticDiagnostics(fileName);
    };
}

