export function decorateLanguageService(
    ls: ts.LanguageService,
    snapshotManager: SvelteSnapshotManager,
    logger: Logger,
    configManager: ConfigManager,
    info: ts.server.PluginCreateInfo,
    typescript: typeof ts,
    onDispose: () => void
) {
    patchedProject.add(info.project.getProjectName());

    // Decorate using a proxy so we can dynamically enable/disable method
    // patches depending on the enabled state of our config
    const proxy = new Proxy(ls, createProxyHandler(configManager));
    decorateLanguageServiceHost(info.languageServiceHost);
    decorateLanguageServiceInner(proxy, snapshotManager, logger, info, typescript, onDispose);

    return proxy;
}

function patchLineColumnOffset(ls: ts.LanguageService, snapshotManager: SvelteSnapshotManager) {
    if (!ls.toLineColumnOffset) {
        return;
    }

    // We need to patch this because (according to source, only) getDefinition uses this
    const toLineColumnOffset = ls.toLineColumnOffset;
    ls.toLineColumnOffset = (fileName, position) => {
        if (isSvelteFilePath(fileName)) {
            const snapshot = snapshotManager.get(fileName);
            if (snapshot) {
                return snapshot.positionAt(position);
            }
        }
        return toLineColumnOffset(fileName, position);
    };
}

function handleDeprecatedOptions(options) {
	const experimental = /** @type {Record<string, any>} */ (options.experimental);
	if (experimental) {
		for (const promoted of ['prebundleSvelteLibraries', 'inspector', 'dynamicCompileOptions']) {
			if (experimental[promoted]) {
				//@ts-expect-error untyped assign
				options[promoted] = experimental[promoted];
				delete experimental[promoted];
				log.warn(
					`Option "experimental.${promoted}" is no longer experimental and has moved to "${promoted}". Please update your Svelte or Vite config.`
				);
			}
		}
	}
}

export function createStateMachine<M>(
	initialState: MachineState<M>,
	machine: M & Machine<MachineState<M>>
) {
	// init a store with the initial state
	const state = withGet.writable(initialState);

	function reducer(event: MachineEvent<M>) {
		const $state = state.get();

		// Get next state based on the current state & event,
		// or keep current state if no transition is defined.
		const nextState = machine[$state][event];
		return nextState ?? $state;
	}

	const dispatch = (event: MachineEvent<M>) => {
		state.set(reducer(event));
	};

	return {
		state,
		dispatch,
	};
}

export function handleScopeAndResolveForSlot({
    identifierDef,
    initExpression,
    owner,
    slotHandler,
    templateScope
}: {
    identifierDef: Node;
    initExpression: Node;
    owner: Node;
    slotHandler: SlotHandler;
    templateScope: TemplateScope;
}) {
    if (isIdentifier(identifierDef)) {
        templateScope.add(identifierDef, owner);

        slotHandler.resolve(identifierDef, initExpression, templateScope);
    }
    if (isDestructuringPatterns(identifierDef)) {
        // the node object is returned as-it with no mutation
        const identifiers = extractIdentifiers(identifierDef) as SvelteIdentifier[];
        templateScope.addMany(identifiers, owner);

        slotHandler.resolveDestructuringAssignment(
            identifierDef,
            identifiers,
            initExpression,
            templateScope
        );
    }
}

export function isKitRouteExportAllowedIn(
    basename: string,
    kitExport: (typeof kitExports)[keyof typeof kitExports]
) {
    if (!basename.startsWith('+')) {
        return false;
    }

    const allowedIn = kitExport.allowedIn;
    return (
        (basename.includes('layout')
            ? allowedIn.includes('layout')
            : basename.includes('+server')
              ? allowedIn.includes('api')
              : allowedIn.includes('page')) &&
        (basename.includes('server')
            ? allowedIn.includes('server')
            : allowedIn.includes('universal'))
    );
}
